import{_ as r,o as a,c as t,a2 as s}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026年5月27日（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-27.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-27.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-27.md"};function i(n,e,l,h,d,p){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="🫘-黃豆追蹤日報-—-2026年5月27日-週三" tabindex="-1">🫘 黃豆追蹤日報 — 2026年5月27日（週三） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026年5月27日-週三" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026年5月27日（週三）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：2026-05-27 05:00 TST（2026-05-26 21:00 UTC） <strong>昨日敘事延續</strong>：美伊和談48小時窗口 → 本週無突破，PGSA新制度實施後通航仍處個位數；肥料（尿素）中斷影響全球農業成本</p></blockquote><hr><h2 id="📊-8項指標檢查" tabindex="-1">📊 8項指標檢查 <a class="header-anchor" href="#📊-8項指標檢查" aria-label="Permalink to &quot;📊 8項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-usda-播種進度報告-—-🔴-有重大進展" tabindex="-1">指標1️⃣ USDA 播種進度報告 — 🔴 有重大進展 <a class="header-anchor" href="#指標1️⃣-usda-播種進度報告-—-🔴-有重大進展" aria-label="Permalink to &quot;指標1️⃣ USDA 播種進度報告 — 🔴 有重大進展&quot;">​</a></h3><p>截至 5/24，美國黃豆種植完成度達 <strong>79%</strong>，遠超五年平均的約 53%（5/17數據），也高於去年同期。主要州別進度：</p><ul><li>威斯康辛：28% → 54%（單週翻倍以上）</li><li>密西根、南北達科他：單週至少種植 25%（儘管密西根前期有濕雨問題）</li><li>全部18個追蹤州中，僅密西根落後五年平均，其餘均超前</li></ul><p>📎 來源：<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a> · <a href="https://southeastagnet.com/2026/05/20/usda-reports-strong-corn-soybean-planting-progress-across-major-states/" target="_blank" rel="noreferrer">Southeast Agnet</a> （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-巴西供應-—-🟢-持續擴張" tabindex="-1">指標2️⃣ 巴西供應 — 🟢 持續擴張 <a class="header-anchor" href="#指標2️⃣-巴西供應-—-🟢-持續擴張" aria-label="Permalink to &quot;指標2️⃣ 巴西供應 — 🟢 持續擴張&quot;">​</a></h3><p>USDA 預測 2026-27 年度全球油籽產量增長，南美豐收供應充足。巴西收割進程順利，出口保持強勁。具體最新數據需等待 CONAB 月度報告。</p><p>📎 來源：<a href="https://www.farmprogress.com/marketing/soybean-futures-surge-as-usda-forecasts-tighter-supplies" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-尿素價格-多單訊號-—-🔴-劇烈波動" tabindex="-1">指標3️⃣ 尿素價格 + 多單訊號 — 🔴 劇烈波動 <a class="header-anchor" href="#指標3️⃣-尿素價格-多單訊號-—-🔴-劇烈波動" aria-label="Permalink to &quot;指標3️⃣ 尿素價格 + 多單訊號 — 🔴 劇烈波動&quot;">​</a></h3><p>荷莫茲海峽自 2/28 封鎖以來，波斯灣地區佔全球尿素出口 30% 以上、伊朗年產 450 萬噸完全斷供。<strong>肥料價格已較封鎖前翻倍以上</strong>。英國議員 5月中旬警告「全球糧食危機」風險，歐盟暫時暫停關鍵氮肥關稅以緩衝供應衝擊。</p><p>📎 來源：<a href="https://time.com/article/2026/05/19/global-food-crisis-concerns-strait-of-hormuz-iran-trade-choke-hold/" target="_blank" rel="noreferrer">Time</a> · <a href="https://www.thepigsite.com/news/2026/05/eu-suspends-fertilizer-tariffs-amid-iran-war-supply-shock" target="_blank" rel="noreferrer">ThePigSite</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-荷莫茲海峽通航狀態-—-🔴-持續緊盯" tabindex="-1">指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 持續緊盯 <a class="header-anchor" href="#指標4️⃣-荷莫茲海峽通航狀態-—-🔴-持續緊盯" aria-label="Permalink to &quot;指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 持續緊盯&quot;">​</a></h3><p><strong>當前狀態</strong>：半封鎖，實際通航接近零至個位數艘/日</p><ul><li>5/20 伊朗設立 PGSA 強制通行許可</li><li>5/26 部分中國船只獲准免費通行，但整體流量远低于危機前（日均 70–138 艘）</li><li>約 1,500 艘滯留船隻的清運是最大障礙</li><li>特朗普表態不急於达成协议，伊朗外交部稱協議「不即將實現」</li></ul><p><strong>對黃豆的影響鏈</strong>：海峽封鎖 → 運費飆升最高 50% + 繞航好望角增加10–20天航程 → 農產品貿易物流受阻 + 化肥供應鏈中斷</p><p>📎 來源：<a href="https://cyprusshippingnews.com/2026/05/26/strait-of-hormuz-transits-increase-slightly-as-iran-us-negotiations-continue/" target="_blank" rel="noreferrer">Cyprus Shipping News</a> · <a href="https://www.businesstimes.com.sg/international/global/even-after-strait-hormuz-deal-moving-1500-ships-wont-be-easy" target="_blank" rel="noreferrer">Business Times SG</a> · <a href="https://reliefweb.int/report/iran-islamic-republic/supply-routes-snapshot-25-may-2026-regional-middle-east-crisis" target="_blank" rel="noreferrer">ReliefWeb</a> （T: 05:00 TST）</p><hr><h3 id="指標5️⃣-中美貿易-中國進口-—-🟡-關注變化" tabindex="-1">指標5️⃣ 中美貿易 + 中國進口 — 🟡 關注變化 <a class="header-anchor" href="#指標5️⃣-中美貿易-中國進口-—-🟡-關注變化" aria-label="Permalink to &quot;指標5️⃣ 中美貿易 + 中國進口 — 🟡 關注變化&quot;">​</a></h3><p>出口銷售數據（截至 5/21）：</p><ul><li>當週新作年度出口銷售 351,423 公噸</li><li>下 Marketing Year 出口銷售 172,729 公噸</li><li>總計 524,152 公噸</li><li>主要買家：日本、墨西哥、韓國、哥倫比亞、西班牙</li><li>大規模標註為「Unknown」目的地</li><li>未來年度出口預估增至 16.30 億蒲式耳（較 25-26 年度 tariff 影響期回升）</li><li>國內压榨紀錄新高 27.50 億蒲式耳（生物燃料需求驅動）</li></ul><p>📎 來源：<a href="https://www.rfdtv.com/traders-await-delayed-crop-progress-report-as-wheat-conditions-remain-under-pressure" target="_blank" rel="noreferrer">RFD-TV</a> （T: 05:00 TST）</p><hr><h3 id="指標6️⃣-天然氣價格-—-🟢-正常區間" tabindex="-1">指標6️⃣ 天然氣價格 — 🟢 正常區間 <a class="header-anchor" href="#指標6️⃣-天然氣價格-—-🟢-正常區間" aria-label="Permalink to &quot;指標6️⃣ 天然氣價格 — 🟢 正常區間&quot;">​</a></h3><p>Henry Hub 現貨 $3.094/MMBtu（+16¢），6月契約 $2.956，7月契約 $3.059。EIA 預測 2026 年平均 $3.64/Mcf。價格平穩未見異常波動。</p><p>📎 來源：<a href="https://www.naturalgasintel.com/news/as-rollover-looms-natural-gas-futures-climbing-despite-comfortable-temps/" target="_blank" rel="noreferrer">Natural Gas Intel</a> · <a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a> （T: 05:00 TST）</p><hr><h3 id="指標7️⃣-聖嬰-拉尼娜氣候風險-—-🟢-無重大變化" tabindex="-1">指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🟢 無重大變化 <a class="header-anchor" href="#指標7️⃣-聖嬰-拉尼娜氣候風險-—-🟢-無重大變化" aria-label="Permalink to &quot;指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🟢 無重大變化&quot;">​</a></h3><p>本日無最新 NOAA 氣候更新發布。持續監測中。</p><p>📎 來源：NOAA （T: 05:00 TST）</p><hr><h3 id="指標8️⃣-cbot-黃豆期貨價格區間-—-🔴-兩年新高分離析" tabindex="-1">指標8️⃣ CBOT 黃豆期貨價格區間 — 🔴 兩年新高分離析 <a class="header-anchor" href="#指標8️⃣-cbot-黃豆期貨價格區間-—-🔴-兩年新高分離析" aria-label="Permalink to &quot;指標8️⃣ CBOT 黃豆期貨價格區間 — 🔴 兩年新高分離析&quot;">​</a></h3><p>CBOT 黃豆 5/26 報價 <strong>$11.855/bu</strong>（跌 0.92%）。注意：</p><ul><li>5/12 WASDE 報告後一度突破 $12/bu，創兩年高點</li><li>7/2026 契約曾觸及 $12.2675（兩月高）</li><li>近期因美中貿易協定不確定性小幅回測 $11.90 以下</li><li>預測季末 ~$12.04，12個月後 ~$12.62</li></ul><p>📎 來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.farmprogress.com/marketing/soybean-futures-surge-as-usda-forecasts-tighter-supplies" target="_blank" rel="noreferrer">Farm Progress</a> · <a href="https://soygrowers.com/news-releases/37753/" target="_blank" rel="noreferrer">SoyGrowers</a> （T: 05:00 TST）</p><hr><h2 id="📰-黃豆即時新聞-5-則" tabindex="-1">📰 黃豆即時新聞 5 則 <a class="header-anchor" href="#📰-黃豆即時新聞-5-則" aria-label="Permalink to &quot;📰 黃豆即時新聞 5 則&quot;">​</a></h2><ol><li><p><strong>[5/26] 黃豆價格下跌但月線仍持平 — 受貿易不確定性拖累</strong> Soybean prices declined to 1185.50 USd/Bu on 5/26 (-0.92%) but remain up 0.70% over past month and 11.58% YoY. Trade uncertainty weighing on near-term sentiment. 📎 <a href="https://www.tradingview.com/news/te_news:553601:0-soybean-prices-extend-decline/" target="_blank" rel="noreferrer">TradingView</a></p></li><li><p><strong>[5/26] 收成近況 — 玉米大豆種植大幅超前五年平均</strong> USDA Crop Progress reports corn at 86% planted, soybeans at 79%, both well ahead of 5-year average across most tracked states. 📎 <a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a></p></li><li><p><strong>[5/20] 中國船只獲准經荷莫茲海峽 — 但不付費用</strong> Certain Chinese vessels reportedly allowed to transit Hormuz without payment under Iran&#39;s new PGSA system, while others face restrictions. 📎 <a href="https://www.unitedagainstnucleariran.com/blog/iran-war-shipping-update-may-22-2026" target="_blank" rel="noreferrer">United Against Nuclear Iran</a></p></li><li><p><strong>[5/19] 聯合國警告全球糧食危機 — 海峽不通则化肥斷供</strong> UK lawmaker warns of looming &quot;global food crisis&quot; if Strait remains closed; EU suspends fertilizer tariffs as emergency measure. 📎 <a href="https://time.com/article/2026/05/19/global-food-crisis-concerns-strait-of-hormuz-iran-trade-choke-hold/" target="_blank" rel="noreferrer">Time</a></p></li><li><p><strong>[5/25] 全球供應鏈路線快照 — 1,500 艘滯留船隻待疏散</strong> Moving even after a Hormuz deal is achieved will take months given logistics of clearing 1,500 stranded ships and demining operations. 📎 <a href="https://www.businesstimes.com.sg/international/global/even-after-strait-hormuz-deal-moving-1500-ships-wont-be-easy" target="_blank" rel="noreferrer">Business Times SG</a></p></li></ol><hr><h2 id="🔮-情景分析" tabindex="-1">🔮 情景分析 <a class="header-anchor" href="#🔮-情景分析" aria-label="Permalink to &quot;🔮 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>黃豆價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>海峽快速重開（和平協議達成）</td><td>30%</td><td>-5~10%</td><td>運費正常化、化肥恢復流通、風險溢價消除</td></tr><tr><td>海峽維持現狀6個月以上</td><td>40%</td><td>+5~15%</td><td>肥料長期短缺壓減产量、運費飆升推高成本、供需緊縮</td></tr><tr><td>衝突升級（全面封鎖）</td><td>20%</td><td>+15~25%</td><td>全球糧食危機、生物燃料需求激增、地緣政治溢價飆升</td></tr><tr><td>漸進式復航（逐步解除）</td><td>10%</td><td>±0~5%</td><td>價格緩步回歸正常區間</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-26): CBOT Soybeans ~$11.855/bu</li><li>Farm Progress (2026-05-26): 全球油籽產量 forecast</li><li>DTN/PF (2026-05-26): USDA Crop Progress – Soybeans 79% planted</li><li>Cyprus Shipping News (2026-05-26): Hormuz transits update</li><li>Natural Gas Intel (2026-05-26): Henry Hub $3.094/MMBtu</li><li>ReliefWeb (2026-05-25): Supply routes snapshot</li></ol>',49)])])}const g=r(o,[["render",i]]);export{u as __pageData,g as default};
